module RefModule(output reg [3:0] offset, input Reset, input Clk2,
    input offsetInc);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge Clk2 or posedge dbg_halt) begin
    if (Reset)
      offset <= 4'b0;
    else
      if (offsetInc)
        offset <= offset + 1;
      else
        offset <= offset;
  end

endmodule
